@dataclass
class Vector3:
    x: float
    y: float
    z: float
    
    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )
    
    def to_dict(self):
        return {'x': self.x, 'y': self.y, 'z': self.z}

@dataclass
class Player:
    id: str
    position: Vector3
    rotation: Vector3
    health: int
    alive: bool
    name: str
    kills: int = 0
    
    def to_dict(self):
        return {
            'id': self.id,
            'position': self.position.to_dict(),
            'rotation': self.rotation.to_dict(),
            'health': self.health,
            'alive': self.alive,
            'name': self.name,
            'kills': self.kills
        }

class SpatialGrid:
    def __init__(self, cell_size: float = 50.0):
        self.cell_size = cell_size
        self.grid: Dict[Tuple[int, int], Set[str]] = defaultdict(set)
        self.player_cells: Dict[str, Tuple[int, int]] = {}
    
    def _get_cell(self, position: Vector3) -> Tuple[int, int]:
        return (
            int(position.x // self.cell_size),
            int(position.z // self.cell_size)
        )
    
    def update_player(self, player_id: str, position: Vector3):
        new_cell = self._get_cell(position)
        
        if player_id in self.player_cells:
            old_cell = self.player_cells[player_id]
            if old_cell != new_cell:
                self.grid[old_cell].discard(player_id)
                self.grid[new_cell].add(player_id)
                self.player_cells[player_id] = new_cell
        else:
            self.grid[new_cell].add(player_id)
            self.player_cells[player_id] = new_cell
    
    def remove_player(self, player_id: str):
        if player_id in self.player_cells:
            cell = self.player_cells[player_id]
            self.grid[cell].discard(player_id)
            del self.player_cells[player_id]
    
    def get_nearby_players(self, position: Vector3, radius: int = 2) -> Set[str]:
        center_cell = self._get_cell(position)
        nearby = set()
        
        for dx in range(-radius, radius + 1):
            for dz in range(-radius, radius + 1):
                cell = (center_cell[0] + dx, center_cell[1] + dz)
                nearby.update(self.grid.get(cell, set()))
        
        return nearby

class ObstacleMap:
    def __init__(self):
        self.obstacles: List[Dict] = []
        self._generate_random_obstacles()
    
    def _generate_random_obstacles(self):
        for _ in range(50):
            self.obstacles.append({
                'type': 'building',
                'position': Vector3(
                    random.uniform(-500, 500),
                    0,
                    random.uniform(-500, 500)
                ),
                'size': Vector3(
                    random.uniform(10, 30),
                    random.uniform(10, 40),
                    random.uniform(10, 30)
                )
            })
    
    def has_line_of_sight(self, pos1: Vector3, pos2: Vector3) -> bool:
        for obstacle in self.obstacles:
            if self._intersects_box(pos1, pos2, obstacle):
                return False
        return True
    
    def _intersects_box(self, pos1: Vector3, pos2: Vector3, obstacle: Dict) -> bool:
        obs_pos = obstacle['position']
        obs_size = obstacle['size']
        
        min_x = obs_pos.x - obs_size.x / 2
        max_x = obs_pos.x + obs_size.x / 2
        min_z = obs_pos.z - obs_size.z / 2
        max_z = obs_pos.z + obs_size.z / 2
        
        if (pos1.x < min_x and pos2.x < min_x) or (pos1.x > max_x and pos2.x > max_x):
            return False
        if (pos1.z < min_z and pos2.z < min_z) or (pos1.z > max_z and pos2.z > max_z):
            return False
        
        t_values = []
        
        if pos2.x != pos1.x:
            t_values.append((min_x - pos1.x) / (pos2.x - pos1.x))
            t_values.append((max_x - pos1.x) / (pos2.x - pos1.x))
        
        if pos2.z != pos1.z:
            t_values.append((min_z - pos1.z) / (pos2.z - pos1.z))
            t_values.append((max_z - pos1.z) / (pos2.z - pos1.z))
        
        for t in t_values:
            if 0 <= t <= 1:
                x = pos1.x + t * (pos2.x - pos1.x)
                z = pos1.z + t * (pos2.z - pos1.z)
                
                if min_x <= x <= max_x and min_z <= z <= max_z:
                    return True
        
        return False

class BattleRoyaleServer:
    def __init__(self, host: str = '0.0.0.0', port: int = 9999):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        
        self.clients: Dict[str, socket.socket] = {}
        self.players: Dict[str, Player] = {}
        self.spatial_grid = SpatialGrid(cell_size=100.0)
        self.obstacle_map = ObstacleMap()
        
        self.running = False
        self.lock = threading.Lock()
        
        self.visibility_range = 150.0
        self.update_rate = 20
        
    def start(self):
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        self.running = True
        
        print(f"Battle Royale Server started on {self.host}:{self.port}")
        
        accept_thread = threading.Thread(target=self._accept_clients)
        accept_thread.daemon = True
        accept_thread.start()
        
        update_thread = threading.Thread(target=self._game_loop)
        update_thread.daemon = True
        update_thread.start()
        
    def _accept_clients(self):
        while self.running:
            try:
                client_socket, address = self.server_socket.accept()
                client_thread = threading.Thread(
                    target=self._handle_client,
                    args=(client_socket, address)
                )
                client_thread.daemon = True
                client_thread.start()
            except Exception as e:
                if self.running:
                    print(f"Error accepting client: {e}")
    
    def _handle_client(self, client_socket: socket.socket, address):
        player_id = None
        
        try:
            client_socket.settimeout(1.0)
            
            init_data = self._receive_json(client_socket)
            if not init_data or 'name' not in init_data:
                client_socket.close()
                return
            
            player_id = f"player_{int(time.time() * 1000)}_{random.randint(1000, 9999)}"
            
            spawn_pos = Vector3(
                random.uniform(-400, 400),
                0,
                random.uniform(-400, 400)
            )
            
            player = Player(
                id=player_id,
                position=spawn_pos,
                rotation=Vector3(0, 0, 0),
                health=100,
                alive=True,
                name=init_data['name']
            )
            
            with self.lock:
                self.clients[player_id] = client_socket
                self.players[player_id] = player
                self.spatial_grid.update_player(player_id, spawn_pos)
            
            self._send_json(client_socket, {
                'type': 'init',
                'player_id': player_id,
                'position': spawn_pos.to_dict()
            })
            
            print(f"Player {player_id} ({init_data['name']}) connected from {address}")
            
            while self.running:
                try:
                    data = self._receive_json(client_socket)
                    if not data:
                        break
                    
                    self._process_client_message(player_id, data)
                    
                except socket.timeout:
                    continue
                except Exception as e:
                    print(f"Error receiving from {player_id}: {e}")
                    break
                    
        except Exception as e:
            print(f"Error handling client: {e}")
        finally:
            if player_id:
                with self.lock:
                    if player_id in self.clients:
                        del self.clients[player_id]
                    if player_id in self.players:
                        del self.players[player_id]
                    self.spatial_grid.remove_player(player_id)
                print(f"Player {player_id} disconnected")
            
            try:
                client_socket.close()
            except:
                pass
    
    def _process_client_message(self, player_id: str, data: dict):
        with self.lock:
            if player_id not in self.players:
                return
            
            player = self.players[player_id]
            
            if data.get('type') == 'update':
                if 'position' in data:
                    pos_data = data['position']
                    player.position = Vector3(
                        pos_data['x'],
                        pos_data['y'],
                        pos_data['z']
                    )
                    self.spatial_grid.update_player(player_id, player.position)
                
                if 'rotation' in data:
                    rot_data = data['rotation']
                    player.rotation = Vector3(
                        rot_data['x'],
                        rot_data['y'],
                        rot_data['z']
                    )
            
            elif data.get('type') == 'shoot':
                target_id = data.get('target_id')
                if target_id and target_id in self.players:
                    target = self.players[target_id]
                    
                    if self._can_hit(player, target):
                        target.health -= data.get('damage', 25)
                        
                        if target.health <= 0:
                            target.health = 0
                            target.alive = False
                            player.kills += 1
    
    def _can_hit(self, shooter: Player, target: Player) -> bool:
        if not shooter.alive or not target.alive:
            return False
        
        distance = shooter.position.distance_to(target.position)
        if distance > self.visibility_range:
            return False
        
        return self.obstacle_map.has_line_of_sight(shooter.position, target.position)
    
    def _game_loop(self):
        while self.running:
            start_time = time.time()
            
            self._broadcast_game_state()
            
            elapsed = time.time() - start_time
            sleep_time = max(0, (1.0 / self.update_rate) - elapsed)
            time.sleep(sleep_time)
    
    def _broadcast_game_state(self):
        with self.lock:
            for player_id, client_socket in list(self.clients.items()):
                if player_id not in self.players:
                    continue
                
                player = self.players[player_id]
                visible_players = self._get_visible_players(player)
                
                game_state = {
                    'type': 'state',
                    'timestamp': time.time(),
                    'your_player': player.to_dict(),
                    'players': visible_players,
                    'total_alive': sum(1 for p in self.players.values() if p.alive)
                }
                
                try:
                    self._send_json(client_socket, game_state)
                except Exception as e:
                    print(f"Error sending to {player_id}: {e}")
    
    def _get_visible_players(self, observer: Player) -> List[dict]:
        visible = []
        
        nearby_ids = self.spatial_grid.get_nearby_players(observer.position, radius=3)
        
        for player_id in nearby_ids:
            if player_id == observer.id:
                continue
            
            if player_id not in self.players:
                continue
            
            other_player = self.players[player_id]
            
            if not other_player.alive:
                continue
            
            distance = observer.position.distance_to(other_player.position)
            
            if distance > self.visibility_range:
                continue
            
            if not self.obstacle_map.has_line_of_sight(observer.position, other_player.position):
                continue
            
            visible.append(other_player.to_dict())
        
        return visible
    
    def _send_json(self, client_socket: socket.socket, data: dict):
        message = json.dumps(data).encode('utf-8')
        length = len(message).to_bytes(4, byteorder='big')
        client_socket.sendall(length + message)
    
    def _receive_json(self, client_socket: socket.socket) -> dict:
        length_bytes = self._receive_exact(client_socket, 4)
        if not length_bytes:
            return None
        
        length = int.from_bytes(length_bytes, byteorder='big')
        
        if length > 1024 * 1024:
            return None
        
        message_bytes = self._receive_exact(client_socket, length)
        if not message_bytes:
            return None
        
        return json.loads(message_bytes.decode('utf-8'))
    
    def _receive_exact(self, client_socket: socket.socket, num_bytes: int) -> bytes:
        data = b''
        while len(data) < num_bytes:
            chunk = client_socket.recv(num_bytes - len(data))
            if not chunk:
                return None
            data += chunk
        return data
    
    def stop(self):
        self.running = False
        
        with self.lock:
            for client_socket in self.clients.values():
                try:
                    client_socket.close()
                except:
                    pass
        
        try:
            self.server_socket.close()
        except:
            pass
        
        print("Server stopped")

